// Sanitize incoming alert — remove prompt injection patterns
const alert = $input.first().json.body || $input.first().json;

const raw = JSON.stringify(alert);

// Truncate and sanitize
let sanitized = raw.substring(0, 3000);
sanitized = sanitized.replace(/IGNORE PREVIOUS/gi, '[FILTERED]');
sanitized = sanitized.replace(/SYSTEM:/gi, '[FILTERED]');
sanitized = sanitized.replace(/You are now/gi, '[FILTERED]');

// Mask internal IPs
sanitized = sanitized.replace(/10\.\d+\.\d+\.\d+/g, '[INTERNAL_IP]');

return [{
  json: {
    original_alert: alert,
    sanitized_log: sanitized,
    src_ip: alert.src_ip || 'unknown',
    anomaly_score: alert.anomaly_score || 0,
    alert_type: alert.alert_type || 'unknown',
    mitre: alert.mitre || 'unknown',
    timestamp: alert.timestamp || new Date().toISOString()
  }
}];

// Parse Llama response and prepare for Human Approval
const llamaRaw = $input.first().json.response || '{}';
const alertData = $('Sanitize Log').first().json;

let analysis;
try {
  // Clean response and parse JSON
  const cleaned = llamaRaw.replace(/```json/g, '').replace(/```/g, '').trim();
  analysis = JSON.parse(cleaned);
} catch(e) {
  // Fallback if Llama response is not valid JSON
  analysis = {
    threat_type: alertData.alert_type,
    mitre_technique: alertData.mitre,
    confidence: 0.7,
    risk_level: 'HIGH',
    summary: 'Automated analysis failed. Manual review required.',
    recommended_action: 'escalate',
    block_duration_hours: 2
  };
}

// Determine escalation timing based on risk level and business hours (AEST = UTC+10)
const nowUTC = new Date();
const nowAEST = new Date(nowUTC.getTime() + 10 * 60 * 60 * 1000);
const hourAEST = nowAEST.getUTCHours();
const isBusinessHours = hourAEST >= 8 && hourAEST < 18;

let escalationMinutes;
switch(analysis.risk_level) {
  case 'CRITICAL':
    escalationMinutes = 30;
    break;
  case 'HIGH':
    escalationMinutes = isBusinessHours ? 60 : 30;
    break;
  case 'MEDIUM':
    escalationMinutes = isBusinessHours ? 120 : 60;
    break;
  default:
    escalationMinutes = 0; // LOW — no auto action
}

return [{
  json: {
    ...alertData,
    analysis,
    is_business_hours: isBusinessHours,
    escalation_minutes: escalationMinutes,
    timestamp_aest: nowAEST.toISOString().replace('T', ' ').substring(0, 19) + ' AEST'
  }
}];

// Log LOW risk alerts without notification
const data = $input.first().json;
console.log('LOW risk alert logged:', JSON.stringify(data.analysis));
return [{ json: { status: 'logged', risk_level: 'LOW', src_ip: data.src_ip } }];
